    bosses: [
      { name: 'Margit the Fell Omen', recLevel: 30, hp: 5000, weaknesses: ['bleed','spirit ashes'], region: 'Limgrave', type: 'Story' },
      { name: 'Godrick the Grafted', recLevel: 35, hp: 6500, weaknesses: ['bleed','poison'], region: 'Stormveil', type: 'Story' },
