      { name: 'Rennala Queen of the Full Moon', recLevel: 45, hp: 5500, weaknesses: ['physical','bleed'], region: 'Liurnia', type: 'Story' },
      { name: 'Starscourge Radahn', recLevel: 65, hp: 9500, weaknesses: ['scarlet rot','bleed','summons'], region: 'Caelid', type: 'Story' },
      { name: 'Draconic Tree Sentinel', recLevel: 70, hp: 8000, weaknesses: ['strike','lightning resist'], region: 'Altus Plateau', type: 'Gate' },
      { name: 'Godfrey Golden Shade', recLevel: 80, hp: 7500, weaknesses: ['physical','lightning'], region: 'Leyndell', type: 'Story' },
      { name: 'Morgott the Omen King', recLevel: 85, hp: 10000, weaknesses: ['bleed','frost'], region: 'Leyndell', type: 'Story' },
      { name: 'Fire Giant', recLevel: 95, hp: 18000, weaknesses: ['frost','bleed','torrent'], region: 'Mountaintops', type: 'Story' },
      { name: 'Godskin Duo', recLevel: 100, hp: 14000, weaknesses: ['sleep','bleed','summons'], region: 'Farum Azula', type: 'Story' },
      { name: 'Maliketh the Black Blade', recLevel: 105, hp: 10500, weaknesses: ['physical','blasphemous claw'], region: 'Farum Azula', type: 'Story' },
      { name: 'Malenia Blade of Miquella', recLevel: 130, hp: 15000, weaknesses: ['bleed','frost','stagger'], region: 'Haligtree', type: 'Optional' },
      { name: 'Mohg Lord of Blood', recLevel: 110, hp: 14000, weaknesses: ['hemorrhage','physick tear'], region: 'Mohgwyn Palace', type: 'Optional' },
      { name: 'Radagon & Elden Beast', recLevel: 120, hp: 20000, weaknesses: ['strike','holy resist'], region: 'Erdtree', type: 'Final' }
    ]
  },
  darkSouls3: {
    name: 'Dark Souls 3',
    bosses: [
      { name: 'Iudex Gundyr', recLevel: 10, hp: 1100, weaknesses: ['fire','parry'], region: 'Cemetery of Ash', type: 'Tutorial' },
      { name: 'Vordt of the Boreal Valley', recLevel: 20, hp: 2500, weaknesses: ['dark','strike'], region: 'High Wall', type: 'Story' },
      { name: 'Abyss Watchers', recLevel: 35, hp: 4500, weaknesses: ['lightning','backstab'], region: 'Farron Keep', type: 'Story' },
      { name: 'Pontiff Sulyvahn', recLevel: 55, hp: 5100, weaknesses: ['parry','lightning','fire'], region: 'Irithyll', type: 'Story' },
      { name: 'Dancer of the Boreal Valley', recLevel: 70, hp: 6000, weaknesses: ['dark','strike'], region: 'Lothric Castle', type: 'Story' },
      { name: 'Nameless King', recLevel: 90, hp: 7000, weaknesses: ['dark','fire'], region: 'Archdragon Peak', type: 'Optional' },
      { name: 'Slave Knight Gael', recLevel: 100, hp: 15000, weaknesses: ['strike','poison','frost'], region: 'Ringed City', type: 'DLC' },
      { name: 'Soul of Cinder', recLevel: 90, hp: 11000, weaknesses: ['lightning','dark'], region: 'Kiln', type: 'Final' }
    ]
  },
  sekiro: {
    name: 'Sekiro: Shadows Die Twice',
    bosses: [
      { name: 'Gyoubu Oniwa', recLevel: 1, hp: 2000, weaknesses: ['firecracker','grapple'], region: 'Ashina Outskirts', type: 'Story' },
      { name: 'Lady Butterfly', recLevel: 1, hp: 1800, weaknesses: ['shuriken','aggression'], region: 'Hirata Estate', type: 'Story' },
      { name: 'Genichiro Ashina', recLevel: 1, hp: 2500, weaknesses: ['mikiri','lightning reversal'], region: 'Ashina Castle', type: 'Story' },
      { name: 'Guardian Ape', recLevel: 1, hp: 3000, weaknesses: ['firecracker','spear'], region: 'Sunken Valley', type: 'Story' },
      { name: 'Owl Father', recLevel: 1, hp: 2800, weaknesses: ['mortal blade','aggression'], region: 'Hirata Estate', type: 'Optional' },
      { name: 'Isshin the Sword Saint', recLevel: 1, hp: 3200, weaknesses: ['mikiri','lightning reversal'], region: 'Ashina Reservoir', type: 'Final' },
      { name: 'Demon of Hatred', recLevel: 1, hp: 3500, weaknesses: ['malcontent','suzaku umbrella'], region: 'Ashina Outskirts', type: 'Optional' }
    ]
  },
  hollowKnight: {
    name: 'Hollow Knight',
    bosses: [
      { name: 'False Knight', recLevel: 10, hp: 800, weaknesses: ['spells','aggression'], region: 'Forgotten Crossroads', type: 'Story' },
      { name: 'Hornet Protector', recLevel: 15, hp: 900, weaknesses: ['vengeful spirit','range'], region: 'Greenpath', type: 'Story' },
      { name: 'Mantis Lords', recLevel: 25, hp: 1600, weaknesses: ['nail arts','quick slash'], region: 'Mantis Village', type: 'Story' },
      { name: 'Broken Vessel', recLevel: 30, hp: 1000, weaknesses: ['spells','defenders crest'], region: 'Ancient Basin', type: 'Story' },
      { name: 'Watcher Knights', recLevel: 35, hp: 1800, weaknesses: ['spells','shade soul'], region: "Watcher's Spire", type: 'Story' },
      { name: 'The Hollow Knight', recLevel: 40, hp: 1300, weaknesses: ['abyss shriek','shade cloak'], region: 'Temple of the Black Egg', type: 'Final' },
      { name: 'Nightmare King Grimm', recLevel: 50, hp: 1500, weaknesses: ['shape of unn','quick focus'], region: 'Dirtmouth', type: 'DLC' },
      { name: 'Absolute Radiance', recLevel: 55, hp: 2000, weaknesses: ['abyss shriek','shaman stone'], region: 'Godhome', type: 'Optional' }
    ]
  }
};

var BUILD_MODS = {
  strength:  { physical: 1.3, fire: 0.9, magic: 0.7 },
  dexterity: { physical: 1.1, bleed: 1.3, magic: 0.8 },
  mage:      { magic: 1.4, physical: 0.6, dark: 1.1 },
  faith:     { holy: 1.4, lightning: 1.2, physical: 0.7 },
  quality:   { physical: 1.2, bleed: 1.0, magic: 0.8 },
  bleed:     { bleed: 1.5, physical: 0.9, magic: 0.7 },
  hybrid:    { physical: 1.0, magic: 1.0, bleed: 1.0 }
};

function calcDifficulty(gameKey, playerLevel, buildType) {
  var game = GAMES[gameKey];
  var build = BUILD_MODS[buildType];
  return game.bosses.map(function(boss) {
    var diff = playerLevel - boss.recLevel;
    var level = diff >= 15 ? 'easy' : diff >= 0 ? 'fair' : diff >= -15 ? 'hard' : 'very hard';
    var adv = 0;
    boss.weaknesses.forEach(function(w) {
      if (build[w] && build[w] > 1.0) adv += build[w] - 1.0;
    });
    var tips = [];
    if (level === 'hard' || level === 'very hard') tips.push('Grind 3-5 more levels');
    if (level === 'very hard') tips.push('Max upgrade weapon & bring consumables');
    if (boss.weaknesses.some(function(w){return w==='bleed';})) tips.push('Bleed build shreds this boss');
    if (boss.weaknesses.some(function(w){return w==='frost';})) tips.push('Frostbite procs deal massive %HP');
    if (adv < 0.05) tips.push('Your build has no advantage here');
    return { name: boss.name, region: boss.region, type: boss.type, recLevel: boss.recLevel, difficulty: level, tips: tips.slice(0, 3), hp: boss.hp };
  });
}

// ── RENDER UI ──
var container = document.currentScript.parentElement;
if (!container) return;
container.innerHTML = '';
container.style.padding = '0';

// Style injection
var style = document.createElement('style');
style.textContent = '.bp-sel{width:100%;padding:10px 12px;border:1px solid #d4d4d8;border-radius:8px;font-size:15px;background:#fff;margin-bottom:12px}.bp-btn{padding:8px 14px;border:2px solid #e4e4e7;border-radius:8px;background:#fff;cursor:pointer;font-size:13px;transition:all .15s;margin:3px}.bp-btn.on{border-color:#2563eb;background:#eff6ff;color:#2563eb;font-weight:600}.bp-row{display:flex;align-items:center;padding:10px 14px;border-bottom:1px solid #f4f4f5;gap:12px;font-size:13px}.bp-tag{padding:2px 8px;border-radius:4px;font-size:11px;font-weight:600;white-space:nowrap}.bp-tag-easy{background:#dcfce7;color:#166534}.bp-tag-fair{background:#fef3c7;color:#92400e}.bp-tag-hard{background:#fee2e2;color:#991b1b}.bp-tag-veryhard{background:#fce7f3;color:#9d174d}.bp-stat{font-size:24px;font-weight:800;text-align:center;padding:8px 16px}.bp-stat-label{font-size:10px;color:#888;text-align:center}';
document.head.appendChild(style);

// Build UI
var html = '<div style="background:#fff;border-radius:12px;overflow:hidden">';

// Header stats placeholder (will update)
html += '<div id="bp-stats" style="display:flex;justify-content:center;gap:24px;padding:20px;background:#f8fafc;border-bottom:1px solid #e2e8f0;flex-wrap:wrap"></div>';

// Controls
html += '<div style="padding:20px;display:flex;flex-wrap:wrap;gap:16px;align-items:end">';

// Game selector
html += '<div style="flex:1;min-width:180px"><label style="font-size:12px;color:#888;margin-bottom:4px;display:block">Game</label><select id="bp-game" class="bp-sel" style="margin:0">';
Object.keys(GAMES).forEach(function(k){ html += '<option value="'+k+'">'+GAMES[k].name+'</option>'; });
html += '</select></div>';

// Level input
html += '<div style="flex:1;min-width:140px"><label style="font-size:12px;color:#888;margin-bottom:4px;display:block">Your Level</label><input id="bp-level" type="number" class="bp-sel" value="50" min="1" max="200" style="margin:0"></div>';

// Build selector
html += '<div style="flex:2;min-width:280px"><label style="font-size:12px;color:#888;margin-bottom:4px;display:block">Build Type</label><div id="bp-builds" style="display:flex;flex-wrap:wrap">';
Object.keys(BUILD_MODS).forEach(function(k, i){ html += '<button class="bp-btn'+(i===0?' on':'')+'" data-build="'+k+'">'+k.charAt(0).toUpperCase()+k.slice(1)+'</button>'; });
html += '</div></div></div>';

// Results table
html += '<div id="bp-results" style="max-height:520px;overflow:auto"></div>';
html += '</div>';
container.innerHTML = html;

// ── Event handlers ──
var selectedGame = 'eldenRing';
var playerLevel = 50;
var buildType = 'strength';

function update() {
  var results = calcDifficulty(selectedGame, playerLevel, buildType);
  var counts = { easy: 0, fair: 0, hard: 0, 'very hard': 0 };
  results.forEach(function(r){ counts[r.difficulty]++; });

  // Update stats
  document.getElementById('bp-stats').innerHTML =
    '<div class="bp-stat" style="color:#166534">'+counts.easy+'<div class="bp-stat-label">Easy</div></div>' +
    '<div class="bp-stat" style="color:#92400e">'+counts.fair+'<div class="bp-stat-label">Fair</div></div>' +
    '<div class="bp-stat" style="color:#991b1b">'+counts.hard+'<div class="bp-stat-label">Hard</div></div>' +
    '<div class="bp-stat" style="color:#9d174d">'+counts['very hard']+'<div class="bp-stat-label">Very Hard</div></div>';

  // Update results table
  var rows = '<div style="font-weight:600;font-size:12px;color:#888;padding:10px 14px;background:#fafafa">Recommended Boss Order — '+GAMES[selectedGame].name+'</div>';
  results.forEach(function(r, i) {
    var tagClass = 'bp-tag-' + r.difficulty.replace(' ', '');
    rows += '<div class="bp-row">' +
      '<span style="color:#888;width:20px">'+(i+1)+'</span>' +
      '<div style="flex:1;min-width:0"><strong>'+r.name+'</strong><div style="font-size:11px;color:#888">'+r.region+' · Rec Lvl '+r.recLevel+'</div></div>' +
      '<span class="bp-tag '+tagClass+'">'+r.difficulty+'</span>' +
      '<span style="font-size:11px;color:#888;text-align:right;max-width:140px" class="bp-tips">'+(r.tips[0]||'')+'</span>' +
    '</div>';
  });
  document.getElementById('bp-results').innerHTML = rows;
}

// Game change
document.getElementById('bp-game').addEventListener('change', function(e) {
  selectedGame = e.target.value;
  update();
});

// Level change
document.getElementById('bp-level').addEventListener('input', function(e) {
  playerLevel = parseInt(e.target.value) || 1;
  update();
});

// Build buttons
document.getElementById('bp-builds').addEventListener('click', function(e) {
  if (e.target.tagName === 'BUTTON') {
    buildType = e.target.dataset.build;
    var btns = document.getElementById('bp-builds').querySelectorAll('button');
    btns.forEach(function(b){ b.classList.remove('on'); });
    e.target.classList.add('on');
    update();
  }
});

// Initial render
update();
})();
